// 容斥原理
void solve(int CASE)
{
	ll n, a, b; cin >> n >> a >> b;
	var w = vector<ll>(n + 1);
	fa(i, 1, n)cin >> w[i];

	var s = Vec2<int>(n + 1, 3);
	var siz = Vec2<ll>(n + 1, 3);
	fa(i, 1, n)fa(j, 0, 2)s[i][j] = i, siz[i][j] = 1;
	var find = [&](var find, int x, int y)->int {
		if (s[x][y] == x)return x;
		return s[x][y] = find(find, s[x][y], y);
		};

	ll ans = n * (n + 1) / 2;
	fa(i, 1, n - 1) {
		int u, v; cin >> u >> v;

		int e1 = find(find, u, 0), e2 = find(find, v, 0);
		if (e1 != e2 and w[u] > a and w[v] > a)
			s[e2][0] = e1, siz[e1][0] += siz[e2][0], siz[e2][0] = 0;

		e1 = find(find, u, 1), e2 = find(find, v, 1);
		if (e1 != e2 and w[u] < b and w[v] < b)
			s[e2][1] = e1, siz[e1][1] += siz[e2][1], siz[e2][1] = 0;

		e1 = find(find, u, 2), e2 = find(find, v, 2);
		if (e1 != e2 and w[u] > a and w[u] < b and w[v] > a and w[v] < b)
			s[e2][2] = e1, siz[e1][2] += siz[e2][2], siz[e2][2] = 0;
	}

	ll res[3] = { 0 };
	fa(i, 1, n)fa(j, 0, 2)res[j] += siz[i][j] * (siz[i][j] + 1) / 2;

	cout << ans - res[0] - res[1] + res[2] << endl;
	return;
}

// 树形dp + 状压dp
void solve(int CASE)
{
	ll n, a, b; cin >> n >> a >> b;
	var w = vector<ll>(n + 1);
	fa(i, 1, n)cin >> w[i];
	var g = vector<vector<int>>(n + 1);
	fa(i, 1, n - 1) {
		int u, v; cin >> u >> v;
		g[u].pb(v), g[v].pb(u);
	}
	var dp = Vec2<ll>(n + 1, 4);
	ll ans = 0;
	var dfs = [&](var dfs, int now, int fa)->void {
		int t = 0;
		if (w[now] > a and w[now] < b)t = 0; // 00
		else if (w[now] <= a)t = 1;          // 01
		else t = 2;                          // 10
		dp[now][t] = 1;

		for (int to : g[now]) {
			if (to == fa)continue;
			dfs(dfs, to, now);

			fa(i, 0, 3)fa(j, 0, 3) 
				if ((i | j) == 3)
					ans += dp[now][i] * dp[to][j];

			fa(j, 0, 3)dp[now][j | t] += dp[to][j];
		}
		};
	dfs(dfs, 1, 0);
	cout << ans << endl;
	return;
}
